{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case P3D_SKELETON_JOINT_FIX_FLAG:
        dch = new tlSkeletonJointBonePreserveChunk16(&ch);
        break;
    case P3D_SKELETON_JOINT_MIRROR_MAP:
        dch = new tlSkeletonJointMirrorMapChunk16(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

